from django.db import transaction
from apps.orders.tasks import send_order_confirmation_email


@transaction.atomic
def order_create(*, user: User, items: list[dict]) -> Order:
    order = Order.objects.create(user=user, status="pending")
    for item in items:
        OrderItem.objects.create(order=order, **item)
    # Fires ONLY after commit
    send_order_confirmation_email.delay_on_commit(order_id=order.id)
    return order

def user_create(*, email: str, password: str) -> User:
    if User.objects.filter(email=email).exists():
        raise ValidationError(f"Email {email} is already registered")
    return User.objects.create_user(email=email, password=password)

# services/order_services.py
@transaction.atomic
def order_create(*, user: User, items: list[dict], payment_gateway) -> Order:
    products = _validate_inventory(items=items)
    order = Order.objects.create(user=user, status="pending")
    total = _create_order_items(order=order, items=items, products=products)
    _deduct_inventory(items=items, products=products)
    order.total = total
    order.save(update_fields=["total", "updated_at"])
    _process_payment(order=order, payment_gateway=payment_gateway)
    send_order_confirmation_email.delay_on_commit(order_id=order.id)
    return order

# views.py  (thin — HTTP only)
class OrderCreateView(APIView):
    def post(self, request):
        serializer = OrderCreateSerializer(data=request.data)
        serializer.is_valid(raise_exception=True)
        try:
            order = order_create(
                user=request.user,
                items=serializer.validated_data["items"],
                payment_gateway=get_payment_gateway(),
            )
            return Response(OrderSerializer(order).data, status=201)
        except InsufficientStockError as e:
            return Response({"error": str(e)}, status=400)
        except PaymentFailedError as e:
            return Response({"error": str(e)}, status=402)
